using HaCreator.MapEditor.Instance.Shapes;using System;using System.Linq;using System.Windows;
namespace HaCreator.GUI.InstanceEditor{public partial class FootholdEditor:EditorBase{private readonly FootholdLine[] footholds;public FootholdEditor(FootholdLine[] footholds){InitializeComponent();this.footholds=footholds;if(footholds.Length==0)return;int? force=footholds[0].Force,piece=footholds[0].Piece;forceEnable.IsChecked=footholds.Any(x=>x.Force!=force)?null:force!=null;if(force.HasValue)InstanceEditorDialogSupport.SetInt(forceInt,force.Value);pieceEnable.IsChecked=footholds.Any(x=>x.Piece!=piece)?null:piece!=null;if(piece.HasValue)InstanceEditorDialogSupport.SetInt(pieceInt,piece.Value);bool cant=footholds[0].CantThrough,fall=footholds[0].ForbidFallDown;cantThroughBox.IsChecked=footholds.Any(x=>x.CantThrough!=cant)?null:cant;forbidFallDownBox.IsChecked=footholds.Any(x=>x.ForbidFallDown!=fall)?null:fall;Force_Changed(null,null);Piece_Changed(null,null);}protected override void cancelButton_Click(object s,EventArgs e)=>Close();protected override void okButton_Click(object s,EventArgs e){if(footholds.Length==0)return;lock(footholds[0].Board.ParentControl){if(forceEnable.IsChecked.HasValue){int? value=forceEnable.IsChecked==true?InstanceEditorDialogSupport.GetInt(forceInt):null;foreach(var line in footholds)line.Force=value;}if(pieceEnable.IsChecked.HasValue){int? value=pieceEnable.IsChecked==true?InstanceEditorDialogSupport.GetInt(pieceInt):null;foreach(var line in footholds)line.Piece=value;}if(cantThroughBox.IsChecked.HasValue)foreach(var line in footholds)line.CantThrough=cantThroughBox.IsChecked.Value;if(forbidFallDownBox.IsChecked.HasValue)foreach(var line in footholds)line.ForbidFallDown=forbidFallDownBox.IsChecked.Value;}Close();}private void Force_Changed(object s,RoutedEventArgs e){if(forceInt!=null)forceInt.IsEnabled=forceEnable.IsChecked==true;}private void Piece_Changed(object s,RoutedEventArgs e){if(pieceInt!=null)pieceInt.IsEnabled=pieceEnable.IsChecked==true;}private void Cancel_Click(object s,RoutedEventArgs e)=>cancelButton_Click(s,EventArgs.Empty);private void Ok_Click(object s,RoutedEventArgs e)=>okButton_Click(s,EventArgs.Empty);}}
